# Script to convert edge trees into dplace trees
# Version 2: Edited by Scott Claessens on 13/04/2026

export CFG=/Users/remco/data/beast/global/dplace

# Step 1: graft in ancient, extinct, colonial and otherwise missing languages
# this adds 57 taxa to the tree
applauncher TreeGrafter -cfg $CFG/glotto_graft_map_v2.cfg -src ~/Downloads/edge6636-March-2023-no-metadata.trees -out edge-grafted.trees

# Step 2: remove all taxa from edge tree that do not have a society associated with its glotto-code
# this leaves 1091 taxa in the tree
applauncher TaxonFilter -subset $CFG/glottocodes_v2.dat -tree edge-grafted.trees -o glotto.trees

applauncher Newick2Nexus -tree glotto.trees -o glotto.nxs

# Step 3: replace taxa with glottocodes by those of societies-sub trees
# and set tip dates to focal times for dplace socieites
applauncher TaxonReplacer -time $CFG/society_id-focal_year_v2.tsv -cfg $CFG/glotto2society_v2.dat -src glotto.nxs -o dplace.trees -maxTime 1.0 
applauncher Newick2Nexus -tree dplace.trees -o dplace.nxs




# Step 4: create human interpretable versions of the tree set
treeannotator -top CCD0 dplace.trees dplace.tree
applauncher TreeRelab -tree dplace.tree -o dplace-relabelled.tree -lab $CFG/soc2label_v2.dat 

treeannotator -height mean dplace.trees dplace.tree
applauncher TreeRelab -tree dplace.tree -o dplace-relabelled.tree -lab $CFG/soc2label_v2.dat 





